package ir.tahamohamadi.resume.api.admin;
import com.fasterxml.jackson.databind.ObjectMapper; import ir.tahamohamadi.audit.event.*; import ir.tahamohamadi.common.audit.AuthenticatedAuditActor; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.resume.*; import org.springframework.data.domain.*; import org.springframework.orm.ObjectOptimisticLockingFailureException; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.time.Instant; import java.util.*; import java.util.stream.Collectors;
@Service @Transactional public class AdminResumeEntryService {private final ResumeEntryRepository entries;private final ResumeEntryTranslationRepository translations;private final AuditEventRepository audit;private final ObjectMapper mapper;private final AuthenticatedAuditActor actor;public AdminResumeEntryService(ResumeEntryRepository entries,ResumeEntryTranslationRepository translations,AuditEventRepository audit,ObjectMapper mapper,AuthenticatedAuditActor actor){this.entries=entries;this.translations=translations;this.audit=audit;this.mapper=mapper;this.actor=actor;}@Transactional(readOnly=true) public Page<AdminResumeEntryResponse> list(int page,int size,String sort){Page<ResumeEntry> values=entries.findByDeletedAtIsNull(paging(page,size,sort));Map<UUID,List<ResumeEntryTranslation>> all=translations.findByEntryIdInAndDeletedAtIsNull(values.getContent().stream().map(ResumeEntry::getId).toList()).stream().collect(Collectors.groupingBy(t->t.getEntry().getId()));return values.map(e->response(e,all.getOrDefault(e.getId(),List.of())));}@Transactional(readOnly=true) public AdminResumeEntryResponse get(UUID id){return response(entry(id));}public AdminResumeEntryResponse create(AdminResumeEntryRequest r){actor.required();Instant now=Instant.now();ResumeEntry e=entries.save(ResumeEntry.create(UUID.randomUUID(),r.entryType(),r.startedOn(),r.endedOn(),r.current(),r.sortOrder(),now));saveTranslations(e,r,now);entries.flush();record("ADMIN_RESUME_ENTRY_CREATED",e.getId());return response(e);}public AdminResumeEntryResponse update(UUID id,AdminResumeEntryRequest r){ResumeEntry e=entry(id);version(e,r.version());Instant now=Instant.now();e.update(r.entryType(),r.startedOn(),r.endedOn(),r.current(),r.sortOrder(),now);saveTranslations(e,r,now);entries.flush();record("ADMIN_RESUME_ENTRY_UPDATED",id);return response(e);}public AdminResumeEntryResponse publish(UUID id,long requested){ResumeEntry e=entry(id);version(e,requested);e.publish(Instant.now());entries.flush();record("ADMIN_RESUME_ENTRY_PUBLISHED",id);return response(e);}public AdminResumeEntryResponse archive(UUID id,long requested){ResumeEntry e=entry(id);version(e,requested);e.archive(Instant.now());entries.flush();record("ADMIN_RESUME_ENTRY_ARCHIVED",id);return response(e);}public void delete(UUID id,long requested){ResumeEntry e=entry(id);version(e,requested);e.softDelete(actor.required(),Instant.now());entries.flush();record("ADMIN_RESUME_ENTRY_DELETED",id);}private ResumeEntry entry(UUID id){return entries.findById(id).filter(e->e.getDeletedAt()==null).orElseThrow(()->new NoSuchElementException("Resume entry not found"));}private void saveTranslations(ResumeEntry e,AdminResumeEntryRequest r,Instant now){List<ResumeEntryTranslation> old=translations.findByEntryIdAndDeletedAtIsNull(e.getId());saveTranslation(e,old,LanguageCode.fa,r.fa(),now);saveTranslation(e,old,LanguageCode.en,r.en(),now);}private void saveTranslation(ResumeEntry e,List<ResumeEntryTranslation> old,LanguageCode lang,AdminResumeTranslationRequest r,Instant now){old.stream().filter(t->t.getLanguageCode()==lang).findFirst().ifPresentOrElse(t->t.update(r.title(),r.organization(),r.location(),r.summary(),now),()->translations.save(ResumeEntryTranslation.create(UUID.randomUUID(),e,lang,r.title(),r.organization(),r.location(),r.summary(),now)));}private AdminResumeEntryResponse response(ResumeEntry e){return response(e,translations.findByEntryIdAndDeletedAtIsNull(e.getId()));}private AdminResumeEntryResponse response(ResumeEntry e,List<ResumeEntryTranslation> t){return new AdminResumeEntryResponse(e.getId(),e.getEntryType(),e.getStatus().name(),e.getStartedOn(),e.getEndedOn(),e.isCurrent(),e.getSortOrder(),translation(t,LanguageCode.fa),translation(t,LanguageCode.en),e.getVersion());}private AdminResumeTranslationRequest translation(List<ResumeEntryTranslation> t,LanguageCode lang){ResumeEntryTranslation x=t.stream().filter(v->v.getLanguageCode()==lang).findFirst().orElseThrow(()->new NoSuchElementException("Resume translation not found"));return new AdminResumeTranslationRequest(x.getTitle(),x.getOrganization(),x.getLocation(),x.getSummary());}private static void version(ResumeEntry e,Long v){if(v==null||e.getVersion()!=v)throw new ObjectOptimisticLockingFailureException(ResumeEntry.class,e.getId());}private static Pageable paging(int page,int size,String sort){String[] p=sort.split(",",-1);if(p.length!=2||!Set.of("sortOrder","startedOn","updatedAt").contains(p[0]))throw new IllegalArgumentException("Unsupported sort");try{return PageRequest.of(page,size,Sort.by(Sort.Direction.fromString(p[1]),p[0]).and(Sort.by("id")));}catch(IllegalArgumentException e){throw new IllegalArgumentException("Unsupported sort");}}private void record(String action,UUID id){audit.save(AuditEvent.record(UUID.randomUUID(),Instant.now(),actor.required(),action,"RESUME_ENTRY",id,"SUCCESS",null,null,mapper.createObjectNode().put("changedFields","managed")));}}
